import { useEffect, useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

function Leads() {
    const [leads, setLeads] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState("");
    const [showDecrypted, setShowDecrypted] = useState(false);
    const navigate = useNavigate();

    const fetchLeads = async (decrypted = false) => {
        setLoading(true); // 🔹 reset loading when button clicked
        setError("");     // 🔹 reset error

        const token = localStorage.getItem("token");
        if (!token) {
            navigate("/");
            return;
        }

        try {
            const res = await axios.get("http://localhost:8000/leads", {
                headers: { Authorization: `Bearer ${token}` },
                params: { decrypted: decrypted ? 1 : 0 }, // 🔹 flag to backend if needed
            });
            setLeads(res.data || []);
        } catch (err) {
            console.error("Error fetching leads:", err);
            if (err.response && err.response.status === 401) {
                setError("Session expired. Please log in again.");
                localStorage.removeItem("token");
                localStorage.removeItem("role");
                navigate("/");
            } else {
                setError("Failed to load leads. Please try again later.");
            }
        } finally {
            setLoading(false);
        }
    };

    // initial fetch
    useEffect(() => {
        fetchLeads(showDecrypted);
    }, []); // only on mount

    const toggleDecrypt = () => {
        setShowDecrypted((prev) => !prev);
        fetchLeads(!showDecrypted); // 🔹 immediately fetch updated data
    };

    if (loading) return <p className="text-center mt-4">Loading leads...</p>;
    if (error) return <p className="text-danger text-center mt-4">{error}</p>;

    return (
        <div className="container mt-4">
            <div className="d-flex justify-content-between align-items-center mb-3">
                <h2 className="mb-0">Leads</h2>
                <button className="btn btn-primary" onClick={toggleDecrypt}>
                    {showDecrypted ? "Show Role-Based" : "Show Decrypted"}
                </button>
            </div>

            {leads.length > 0 ? (
                <table className="table table-striped table-bordered">
                    <thead className="table-dark">
                        <tr>
                            <th>Name</th>
                            <th>Username</th>
                            <th>Email</th>
                            <th>Phone</th>
                            <th>Company URL</th>
                            <th>Company Name</th>
                        </tr>
                    </thead>
                    <tbody>
                        {leads.map((lead) => (
                            <tr key={lead.id}>
                                <td>{lead.name || "-"}</td>
                                <td>{lead.username || "-"}</td>
                                <td>{lead.email || "-"}</td>
                                <td>{lead.phone || "-"}</td>
                                <td>{lead.link_url || "-"}</td>
                                <td>{lead.company_name || "-"}</td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            ) : (
                <p className="text-muted">No leads found.</p>
            )}
        </div>
    );
}

export default Leads;
